136	    }
137	    const policy = policies[step.policy as number];
138	    const payout = payoutForClaim(step.incident as Incident);
139	    policy.remainingCap -= payout;
140	    return { payout, remainingCap: policy.remainingCap };
141	  });
142	  return { results };
