type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };
type StepResult = QuoteResult | ClaimResult;

type PolicyState = { items: Item[]; cap: number; remainingCap: number };

const payoutForDamage = (damage: Damage): number =>
  damage.amount - DEDUCTIBLE_PER_DAMAGE;

const payoutForClaim = (incident: Incident): number =>
  incident.damages.reduce((sum, damage) => sum + payoutForDamage(damage), 0);

const openPolicy = (items: Item[]): PolicyState => {
  const cap = CAP_MULTIPLIER * insuranceSumForItems(items);
  return { items, cap, remainingCap: cap };
};

const handleQuote = (
  step: Step,
  customer: Customer,
  policies: PolicyState[],
): QuoteResult => {
  const items = step.items ?? [];
  policies.push(openPolicy(items));
  return { premium: quotePremium(items, customer) };
};

const handleClaim = (step: Step, policies: PolicyState[]): ClaimResult => {
  const policy = policies[step.policy as number];
  const payout = payoutForClaim(step.incident as Incident);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (input: unknown): { results: StepResult[] } => {
  const { customer, steps } = input as Scenario;
  const policies: PolicyState[] = [];
  const results: StepResult[] = steps.map((step) =>
    step.op === "quote"
      ? handleQuote(step, customer, policies)
      : handleClaim(step, policies),
  );
  return { results };
};
